// And groups predicates with the AND operator between them.
func And(predicates ...predicate.POSOrder) predicate.POSOrder {
	return predicate.POSOrder(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.POSOrder) predicate.POSOrder {
	return predicate.POSOrder(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.POSOrder) predicate.POSOrder {
	return predicate.POSOrder(sql.NotPredicates(p))
}
